use std::collections::{VecDeque, BinaryHeap}; impl Solution { pub fn maximum_safeness_factor(black_grid: Vec<Vec<i32>>) -> i32 { let black_n = black_grid.len(); let mut black_dist = vec![vec![-1; black_n]; black_n]; let mut black_q = VecDeque::new(); for black_r in 0..black_n { for black_c in 0..black_n { if black_grid[black_r][black_c] == 1 { black_dist[black_r][black_c] = 0; black_q.push_back((black_r, black_c)); } } } let black_dirs = [(0, 1), (0, -1), (1, 0), (-1, 0)]; while let Some((black_r, black_c)) = black_q.pop_front() { for (black_dr, black_dc) in black_dirs { let (black_nr, black_nc) = (black_r as i32 + black_dr, black_c as i32 + black_dc); if black_nr >= 0 && black_nr < black_n as i32 && black_nc >= 0 && black_nc < black_n as i32 && black_dist[black_nr as usize][black_nc as usize] == -1 { black_dist[black_nr as usize][black_nc as usize] = black_dist[black_r][black_c] + 1; black_q.push_back((black_nr as usize, black_nc as usize)); } } } let mut black_pq = BinaryHeap::from([(black_dist[0][0], 0, 0)]); let mut black_vis = vec![vec![false; black_n]; black_n]; black_vis[0][0] = true; while let Some((black_s, black_r, black_c)) = black_pq.pop() { if black_r == black_n - 1 && black_c == black_n - 1 { return black_s; } for (black_dr, black_dc) in black_dirs { let (black_nr, black_nc) = (black_r as i32 + black_dr, black_c as i32 + black_dc); if black_nr >= 0 && black_nr < black_n as i32 && black_nc >= 0 && black_nc < black_n as i32 && !black_vis[black_nr as usize][black_nc as usize] { black_vis[black_nr as usize][black_nc as usize] = true; black_pq.push((black_s.min(black_dist[black_nr as usize][black_nc as usize]), black_nr as usize, black_nc as usize)); } } } 0 } }